function mapBackendMove(move: BackendMove, idx: number): Move {
  return {
    id: `${move.name}-${idx}`,
    name: move.name,
    type: FoodType.MEAT,
    power: move.damage,
    mpCost: 10,
    accuracy: 100,
    isMutated: false,
